"""matplotlib.collections — collection stubs."""

import numpy as _np


class Collection:
    def __init__(self, **kwargs):
        self._facecolors = kwargs.get('facecolors', [])
        self._edgecolors = kwargs.get('edgecolors', [])
        self._linewidths = kwargs.get('linewidths', [1.0])
        self._alpha = kwargs.get('alpha', None)
    def set_alpha(self, a): self._alpha = a
    def set_facecolor(self, c): self._facecolors = c
    def set_edgecolor(self, c): self._edgecolors = c
    def get_facecolor(self): return self._facecolors
    def get_edgecolor(self): return self._edgecolors
    def set_array(self, A): self._A = A
    def get_array(self): return getattr(self, '_A', None)
    def set_clim(self, vmin=None, vmax=None): pass
    def set_cmap(self, cmap): pass
    def set_visible(self, v): pass
    def remove(self): pass


class PathCollection(Collection):
    """Scatter plot collection."""
    def __init__(self, paths=None, **kwargs):
        super().__init__(**kwargs)
        self._paths = paths
        self._offsets = kwargs.get('offsets', _np.empty((0, 2)))
        self._sizes = kwargs.get('sizes', [20])

    def get_offsets(self): return self._offsets
    def set_offsets(self, offsets): self._offsets = offsets
    def get_sizes(self): return self._sizes
    def set_sizes(self, sizes): self._sizes = sizes
    def legend_elements(self, prop='colors', num='auto', **kwargs):
        return [], []


class LineCollection(Collection):
    def __init__(self, segments=None, **kwargs):
        super().__init__(**kwargs)
        self._segments = segments

    def set_segments(self, segments): self._segments = segments
    def get_segments(self): return self._segments


class PolyCollection(Collection):
    def __init__(self, verts=None, **kwargs):
        super().__init__(**kwargs)
        self._verts = verts


class QuadMesh(Collection):
    pass


class PatchCollection(Collection):
    def __init__(self, patches=None, **kwargs):
        super().__init__(**kwargs)
        self._patches = patches or []


class EventCollection(Collection):
    def __init__(self, positions=None, **kwargs):
        super().__init__(**kwargs)
        self._positions = positions


class EllipseCollection(Collection):
    pass


class TriMesh(Collection):
    pass
